#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {
    // Flattened pointers for fast access and to avoid bounds checks
    const size_t strideC = n;
    const size_t strideA = m;

    // Parallelise over the rows of C; each row is independent
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* Ci = &C[i][0];            // pointer to the i‑th row of C
        const double* Ai = &A[i][0];      // pointer to the i‑th row of A

        // Scale the lower triangle of the current row by beta
        for (int j = 0; j <= i; ++j) {
            Ci[j] *= beta;
        }

        // Outer loop over columns of A (k dimension)
        for (int k = 0; k < m; ++k) {
            double aik = Ai[k];            // A[i][k]
            // Inner loop over j <= i
            // Unroll by 4 for a modest speedup
            int j = 0;
            for (; j <= i - 3; j += 4) {
                Ci[j]     += alpha * aik * A[j][k];
                Ci[j + 1] += alpha * aik * A[j + 1][k];
                Ci[j + 2] += alpha * aik * A[j + 2][k];
                Ci[j + 3] += alpha * aik * A[j + 3][k];
            }
            for (; j <= i; ++j) {
                Ci[j] += alpha * aik * A[j][k];
            }
        }
    }
}
