/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    // Acquire raw pointers to the underlying data for fastest access
    const double* const* Ap = reinterpret_cast<const double* const*>(&A[0]);
    const double* const* Bp = reinterpret_cast<const double* const*>(&B[0]);

    // Parallelise over the outer loop; work is naturally independent per row.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const double* Ai = Ap[i];
        const double* Bi = Bp[i];
        const double* Xi = &x[0];

        double tmp_i = 0.0;
        double y_i   = 0.0;

        // Inner loop fused: compute both tmp[i] and y[i]
        #pragma omp simd reduction(+:tmp_i,y_i)
        for (int j = 0; j < n; ++j) {
            double xj   = Xi[j];
            tmp_i += Ai[j] * xj;
            y_i   += Bi[j] * xj;
        }

        // Store results and apply scaling
        tmp[i] = tmp_i;
        y[i]   = alpha * tmp_i + beta * y_i;
    }
}
