/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    /* Convert the 2‑D std::vector layout into simple ragged
     * pointers for fast inner‑loop access.  The outer dimension
     * is contiguous so the overhead of vector indexing is
     * paid only once per row.  */
    double **Cp = new double*[m];
    double **Ap = new double*[m];
    double **Bp = new double*[m];
    for (int i = 0; i < m; ++i) {
        Cp[i] = C[i].data();
        Ap[i] = A[i].data();
        Bp[i] = B[i].data();
    }

    /* Parallelise over rows of C (i).  The inner j‑loop is
     * cache friendly because B[i][*] and A[i][*] are accessed
     * sequentially.  */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        const double *Ai = Ap[i];      // row i of A
        const double *Bi = Bp[i];      // row i of B
        for (int j = 0; j < n; ++j) {
            double temp2 = 0.0;
            double Bj = Bi[j];
            for (int k = 0; k < i; ++k) {
                double aik = Ai[k];
                Cp[k][j] += alpha * Bj * aik;
                temp2 += Bp[k][j] * aik;
            }
            Cp[i][j] = beta * Cp[i][j] + alpha * Bj * Ai[i] + alpha * temp2;
        }
    }

    delete[] Cp;
    delete[] Ap;
    delete[] Bp;
}
