/* Main computational kernel. The whole function will be timed,
   including the call and return. */

void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b)
{
    // Pointers to the underlying memory for faster access
    double **Lptr = new double*[n];
    for (int i = 0; i < n; ++i) {
        Lptr[i] = L[i].data();
    }
    double *xptr = x.data();
    double *bptr = b.data();

    // Forward substitution: single threaded because of data dependency
    for (int i = 0; i < n; ++i) {
        double sum = bptr[i];
        double *Lrow = Lptr[i];
        double *xrow = xptr;

        // Unrolled inner loop (4x).  The remaining elements are handled
        // by a scalar loop.
        int j = 0;
        int limit = i - (i % 4);
        for (; j < limit; j += 4) {
            sum -= Lrow[j]   * xrow[j];
            sum -= Lrow[j+1] * xrow[j+1];
            sum -= Lrow[j+2] * xrow[j+2];
            sum -= Lrow[j+3] * xrow[j+3];
        }
        for (; j < i; ++j) {
            sum -= Lrow[j] * xrow[j];
        }

        xptr[i] = sum / Lrow[i];
    }

    delete[] Lptr;
}
