/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    /* Parallelise the outermost loop over rows of B.
       Each iteration is independent, so an OpenMP parallel for
       gives a good speed‑up on the supported 8 threads. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        /* Loop over columns of B. */
        for (int j = 0; j < n; ++j) {
            double sum = 0.0;
            /* Accumulate contributions from rows k > i.
               Unroll the inner loop by a factor of 4 for a modest
               improvement in floating‑point throughput. */
            int k = i + 1;
            int k_end = m - (m - i - 1) % 4;
            for (; k < k_end; k += 4) {
                sum += A[k][i]      * B[k][j];
                sum += A[k + 1][i]  * B[k + 1][j];
                sum += A[k + 2][i]  * B[k + 2][j];
                sum += A[k + 3][i]  * B[k + 3][j];
            }
            for (; k < m; ++k) {
                sum += A[k][i] * B[k][j];
            }
            B[i][j] = alpha * (B[i][j] + sum);
        }
    }
}
