#include <cstring>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y)
{
    // Allocate a temporary buffer once.  The array is large enough for all
    // iterations; its contents are overwritten each iteration.
    std::vector<double> z(n);

    // First element of the output sequence
    y[0] = -r[0];

    // Scalars that survive across iterations
    double beta  = 1.0;
    double alpha = -r[0];

    // For speed the inner loops are written with raw indexing and
    // pointer arithmetic; no bounds checks or temporaries are created.
    for (int k = 1; k < n; ++k) {
        // Update beta
        beta = (1.0 - alpha * alpha) * beta;

        // Compute the inner product sum = Σ r[k-i-1] * y[i]
        double sum = 0.0;
        int idx = k - 1;                 // r index starts at k-1
        int yi  = 0;                     // y index starts at 0
        for (int i = 0; i < k; ++i, --idx, ++yi) {
            sum += r[idx] * y[yi];
        }

        // New reflection coefficient
        alpha = -(r[k] + sum) / beta;

        // Update y using a temporary buffer z
        idx = k - 1;
        yi  = 0;
        for (int i = 0; i < k; ++i, --idx, ++yi) {
            z[i] = y[yi] + alpha * y[idx];
        }

        // Copy back
        std::memcpy(y.data(), z.data(), k * sizeof(double));

        // Finalize current element
        y[k] = alpha;
    }
}
