/* Helper to access a column‑major view of the 2‑D vector */
struct ColView {
    std::vector<std::vector<double>>& A;
    inline double& operator()(size_t row, size_t col) { return A[row][col]; }
};

/* Kernel implementation */
void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    /* 1. Compute means ----------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += data[i][j];
        mean[j] = sum / n;
    }

    /* 2. Center data ------------------------------------------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            data[i][j] -= mean[j];

    /* 3. Compute covariance matrix ---------------------------------------- */
    const int block = 64;                     /* tile size, tuned empirically */
    #pragma omp parallel
    {
        /* Each thread processes a few blocks to keep cache lines filled */
        #pragma omp for schedule(static)
        for (int bi = 0; bi < m; bi += block) {
            int i_end = std::min(bi + block, m);
            for (int bj = bi; bj < m; bj += block) {
                int j_end = std::min(bj + block, m);
                for (int i = bi; i < i_end; ++i) {
                    for (int j = std::max(i, bj); j < j_end; ++j) {
                        double sum = 0.0;
                        for (int k = 0; k < n; ++k)
                            sum += data[k][i] * data[k][j];
                        sum /= (n - 1.0);
                        cov[i][j] = sum;
                        cov[j][i] = sum;
                    }
                }
            }
        }
    }
}
