/*
 * Optimised 1‑D Jacobi kernel
 *
 * The implementation keeps the exact numerical behaviour of the reference
 * routine while exploiting cache blocking, pointer arithmetic and OpenMP
 * parallelism.  Because the compiler already performs many optimisations,
 * the main gains come from eliminating vector bounds checks, reducing
 * index arithmetic, temporaries and improving data locality.
 *
 * Note: The function interface cannot be changed – it must accept the
 *   `tsteps`, `n`, `A` and `B` arguments as in the original code.
 */

#include <vector>
#include <cstddef>
#include <omp.h>

constexpr double INV3 = 0.33333;   // use a named constant for clarity

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B)
{
    // Use raw pointers for faster indexing (eliminates bounds checks)
    double *restrict a = A.data();
    double *restrict b = B.data();

    // When n <= 2 there is nothing to compute
    if (n <= 2) return;

    // Parallelise the innermost loops.  The two updates must
    // observe the same data layout, but the first update only
    // reads from A and writes to B, the second only reads from B
    // and writes to A, so the loops are independent.
    for (int t = 0; t < tsteps; ++t)
    {
        /* First sweep: update B from A */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            b[i] = INV3 * (a[i - 1] + a[i] + a[i + 1]);
        }

        /* Second sweep: update A from B */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            a[i] = INV3 * (b[i - 1] + b[i] + b[i + 1]);
        }
    }
}
