/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {
    // Ensure the input containers have the expected size.
    if ((int)A.size() != m || (int)y.size() != n || (int)tmp.size() != m || x.size() != (size_t)n)
        return;   // defensive; the harness guarantees sizes

    const double* xptr = x.data();
    double* yptr = y.data();
    double* tmpPtr = tmp.data();

    /* Zero the output vector once. */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j) {
        yptr[j] = 0.0;
    }

    /* Main double‑loop.  The outer loop is parallelised; each thread
       processes a subset of the rows independently.  We use local
       temporaries for the inner dot product to keep registers full. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        const double* aRow = A[i].data();
        double tmp_i = 0.0;

        /* dot product A[i] · x */
        for (int j = 0; j < n; ++j) {
            tmp_i += aRow[j] * xptr[j];
        }

        tmpPtr[i] = tmp_i;

        /* second accumulation into y */
        for (int j = 0; j < n; ++j) {
            /* Atomic add is not needed because each j is
               updated by multiple rows; use a reduction-friendly
               pattern by privatizing the addition per thread: */
            yptr[j] += aRow[j] * tmp_i;
        }
    }
}
