/* Helper to expose the underlying data pointer
   while keeping the interface identical. */
static inline double* data_ptr(std::vector<std::vector<double>>& A, size_t i, size_t j) {
    return &A[i][j];
}

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_seidel_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A) {
    /* use aliased pointers to improve locality and SIMD friendliness */
    const size_t stride = A[0].size();
    /* create a second buffer to read/write values on successive steps
       without disturbing the values needed for the current step. */
    std::vector<double> buf((n) * (n), 0.0);

    /* copy original data into the buffer */
    for (int i = 0; i < n; ++i)
        std::memcpy(&buf[i * stride], A[i].data(), stride * sizeof(double));

    /* precompute reciprocal */
    const double inv9 = 1.0 / 9.0;

    /* main time-loop */
    for (int step = 0; step < tsteps; ++step) {
        /* Parallelise over rows (i) and keep inner loop over columns (j) to
           preserve the data dependencies of the red–black style update. */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i <= n - 2; ++i) {
            double* row_above    = &buf[(i - 1) * stride];
            double* row_current  = &buf[i * stride];
            double* row_below    = &buf[(i + 1) * stride];
            for (int j = 1; j <= n - 2; ++j) {
                /* sum of the 3x3 neighbourhood */
                double s =  row_above[j - 1] + row_above[j] + row_above[j + 1] +
                            row_current[j - 1] + row_current[j] + row_current[j + 1] +
                            row_below[j - 1] + row_below[j] + row_below[j + 1];
                row_current[j] = s * inv9;
            }
        }
    }

    /* copy results back into the original 2‑D vector */
    for (int i = 0; i < n; ++i)
        std::memcpy(A[i].data(), &buf[i * stride], stride * sizeof(double));
}
