/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n,
                     std::vector<std::vector<double>>& A) {
    // Reduce cache misses by acquiring pointers once
    for (int i = 0; i < n; ++i) {
        double* Ai = A[i].data();          // row i
        // Probe rows 0..i-1; they are already complete
        const int im1 = i - 1;

        /* ------------------------------------------------------------------
           The lower–triangle elements (j < i) can be computed independently
           for each j because they only read already–finished rows A[j][*]
           and the current row A[i][*] below the diagonal (which is still
           untouched).  Therefore, we loop over j in parallel.
        ------------------------------------------------------------------ */
#pragma omp parallel for schedule(static)
        for (int j = 0; j < i; ++j) {
            double* Aj = A[j].data();      // row j
            double sum = 0.0;

            // inner k-loop
            for (int k = 0; k < j; ++k)
                sum += Ai[k] * Aj[k];

            Ai[j] = (Ai[j] - sum) / Aj[j];
        }

        /* ------------------------------------------------------------------
           Compute the diagonal element A[i][i].
        ------------------------------------------------------------------ */
        double sum = 0.0;
        for (int k = 0; k < i; ++k)
            sum += Ai[k] * Ai[k];

        Ai[i] -= sum;
        Ai[i] = std::sqrt(Ai[i]);
    }
}
