#include <algorithm>
#include <omp.h>

//------------------------------------------------------------------------------
// Floyd‑Warshall with contiguous storage and OpenMP on the inner i‑loop.
//------------------------------------------------------------------------------
// The function keeps the original signature.  Internally it copies the matrix
// into a flat contiguous array, performs the algorithm using raw pointers
// for maximum speed, and finally copies the result back to the caller’s
// vector< vector<int> >.
//
// Note: The algorithm is cache‑friendly because the flat array is laid out
// row‑major, matching the layout used by the input vector of vectors.
//------------------------------------------------------------------------------
inline void kernel_floyd_warshall(int n,
                                  std::vector<std::vector<int>>& path) {
    // 1. Flatten the vector of vectors into a contiguous array.
    std::vector<int> flat(n * n);          // temporary storage
    for (int i = 0; i < n; ++i) {
        std::memcpy(&flat[i * n], path[i].data(), n * sizeof(int));
    }

    // 2. Alias for easier pointer arithmetic.
    int* a = flat.data();

    // 3. Main algorithm.  The outer k‑loop remains serial because of the
    //    data dependences.  The i‑loop is parallelised with OpenMP.
    //    We use register variables where possible and disable bounds
    //    checks by working with raw pointers.
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        int* ai = a + i * n;          // start of row i

        for (int k = 0; k < n; ++k) {
            int aik = ai[k];          // a[i][k] – fetched once per k

            if (aik == INT_MAX) continue; // skip unnecessary work

            // Precompute the start of row k for reuse
            const int* ak = a + k * n;

            for (int j = 0; j < n; ++j) {
                // a[i][j] = min(a[i][j], a[i][k] + a[k][j])
                int alt = aik + ak[j];
                if (alt < ai[j]) ai[j] = alt;
            }
        }
    }

    // 4. Copy the result back to the user‑provided vector.
    for (int i = 0; i < n; ++i) {
        std::memcpy(path[i].data(), &flat[i * n], n * sizeof(int));
    }
}
