#include <vector>
#include <omp.h>
#include <cstring>   // for memcpy

// The original signature must stay exactly the same.
void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C) {

    /* 1.  Work on flat 1‑D arrays (row major) to avoid double indirection
     *    and guarantee contiguous memory access (cache friendly).    */
    const std::size_t a_nm = static_cast<std::size_t>(ni) * nk;
    const std::size_t b_nm = static_cast<std::size_t>(nk) * nj;
    const std::size_t c_nm = static_cast<std::size_t>(ni) * nj;

    std::vector<double> a_flat(a_nm);
    std::vector<double> b_flat(b_nm);
    std::vector<double> c_flat(c_nm);

    for (int i = 0; i < ni; ++i)
        std::memcpy(&a_flat[i * nk], A[i].data(), nk * sizeof(double));

    for (int k = 0; k < nk; ++k)
        std::memcpy(&b_flat[k * nj], B[k].data(), nj * sizeof(double));

    // Copy the input C into the flat array
    for (int i = 0; i < ni; ++i)
        std::memcpy(&c_flat[i * nj], C[i].data(), nj * sizeof(double));

    /* 2.  Parallelise the outermost loop with a team of 8 threads
     *     (or whatever the runtime decides based on OMP_NUM_THREADS). */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* c_row = &c_flat[i * nj];
        const double* a_row = &a_flat[i * nk];

        /* 3.  Scale C[i, :] by beta.
         *     A small loop, but benefits from a local pointer. */
        for (int j = 0; j < nj; ++j) {
            c_row[j] *= beta;
        }

        /* 4.  Write the kernel loop in a cache‑friendly order:
         *     iterate k first, then j. This ensures that
         *     B[k,*] is accessed sequentially for each k.        */
        for (int k = 0; k < nk; ++k) {
            const double aik = alpha * a_row[k];
            const double* b_row = &b_flat[k * nj];
            for (int j = 0; j < nj; ++j) {
                c_row[j] += aik * b_row[j];
            }
        }
    }

    /* 5.  Write the result back to the original C vector of vectors. */
    for (int i = 0; i < ni; ++i)
        std::memcpy(C[i].data(), &c_flat[i * nj], nj * sizeof(double));
}
