```cpp
#include <cmath>
#include <vector>
#include <algorithm>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q)
{
    // We flatten the 2‑D vectors in row‑major order to eliminate bound checks
    // and improve cache locality.
    const std::size_t mn = static_cast<std::size_t>(m) * n;
    std::vector<double> flatA(mn), flatQ(mn);           // temporary copies of A and Q
    std::vector<double*> colA(n, nullptr);              // pointers to columns of flatA
    std::vector<double*> colQ(n, nullptr);              // pointers to columns of flatQ

    // Initial copy from the 2‑D Eigen‑like representation
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < n; ++j)
            flatA[i * n + j] = A[i][j];

    for (int j = 0; j < n; ++j) {
        colA[j] = &flatA[j];          // column j starts at offset j
        colQ[j] = &flatQ[j];
    }

    for (int k = 0; k < n; ++k) {
        // compute norm of column k
        double nrm = 0.0;
        const double* pk = colA[k];
#pragma omp simd reduction(+:nrm)
        for (int i = 0; i < m; ++i)
            nrm += pk[i] * pk[i];

        R[k][k] = std::sqrt(nrm);
        const double inv = 1.0 / R[k][k];

        // Q(:,k) = A(:,k) / R(k,k)
        double* qk = colQ[k];
#pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i)
            qk[i] = pk[i] * inv;

        // for j > k
        for (int j = k + 1; j < n; ++j) {
            // R(k,j) = Q(:,k)^T * A(:,j)
            const double* pj = colA[j];
            double dot = 0.0;
#pragma omp simd reduction(+:dot)
            for (int i = 0; i < m; ++i)
                dot += qk[i] * pj[i];
            R[k][j] = dot;

            // A(:,j) -= Q(:,k) * R(k,j)
            double* aj = colA[j];
#pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i)
                aj[i] -= qk[i] * dot;
        }
    }

    // Write back the Q matrix
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < n; ++j)
            Q[i][j] = flatQ[i * n + j];
}
