/* Main computational kernel. The whole function will be timed,
   including the call and return.  */
void kernel_fdtd_2d(int tmax,
                    int nx,
                    int ny,
                    std::vector<std::vector<double>>& ex,
                    std::vector<std::vector<double>>& ey,
                    std::vector<std::vector<double>>& hz,
                    std::vector<double>& _fict_) {
    const double half = 0.5;
    const double coeff = 0.7;

    for (int t = 0; t < tmax; ++t) {
        double fict_t = _fict_[t];

        /* 1. Update ey[0][j] */
#pragma omp parallel for
        for (int j = 0; j < ny; ++j)
            ey[0][j] = fict_t;

        /* 2. Update ey[i][j] for i >= 1 */
#pragma omp parallel for collapse(2)
        for (int i = 1; i < nx; ++i) {
            for (int j = 0; j < ny; ++j) {
                ey[i][j] -= half * (hz[i][j] - hz[i - 1][j]);
            }
        }

        /* 3. Update ex[i][j] for j >= 1 */
#pragma omp parallel for collapse(2)
        for (int i = 0; i < nx; ++i) {
            for (int j = 1; j < ny; ++j) {
                ex[i][j] -= half * (hz[i][j] - hz[i][j - 1]);
            }
        }

        /* 4. Update hz[i][j] leaving last row/col */
#pragma omp parallel for collapse(2)
        for (int i = 0; i < nx - 1; ++i) {
            for (int j = 0; j < ny - 1; ++j) {
                hz[i][j] -= coeff *
                    (ex[i][j + 1] - ex[i][j] + ey[i + 1][j] - ey[i][j]);
            }
        }
    }
}
