// Main computational kernel. The whole function will be timed,
// including the call and return.
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z)
{
    // ------------------------------------------------------------------
    // 1) A <- A + u1*v1^T + u2*v2^T
    // ------------------------------------------------------------------
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < n; ++i)
    {
        const double ui1 = u1[i];
        const double ui2 = u2[i];
        std::vector<double> &Ai = A[i];
        for (int j = 0; j < n; ++j)
        {
            Ai[j] += ui1 * v1[j] + ui2 * v2[j];
        }
    }

    // ------------------------------------------------------------------
    // 2) x <- x + beta * A^T * y
    // ------------------------------------------------------------------
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < n; ++i)  // columns of A (original rows of A^T)
    {
        double xi = x[i];
        for (int j = 0; j < n; ++j) // rows of A (original columns of A^T)
        {
            xi += beta * A[j][i] * y[j];
        }
        x[i] = xi;
    }

    // ------------------------------------------------------------------
    // 3) x <- x + z
    // ------------------------------------------------------------------
    #pragma omp parallel for
    for (int i = 0; i < n; ++i)
    {
        x[i] += z[i];
    }

    // ------------------------------------------------------------------
    // 4) w <- w + alpha * A * x
    // ------------------------------------------------------------------
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < n; ++i)          // rows of A
    {
        double wi = w[i];
        const std::vector<double> &Ai = A[i];
        for (int j = 0; j < n; ++j)      // columns of A
        {
            wi += alpha * Ai[j] * x[j];
        }
        w[i] = wi;
    }
}
