/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_3mm(int ni, int nj, int nk, int nl, int nm,
                std::vector<std::vector<double>>& E,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& F,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D,
                std::vector<std::vector<double>>& G)
{
    // Flatten the 2‑D vectors into 1‑D pointers for contiguous access.
    const double* a = &A[0][0];
    const double* b = &B[0][0];
    const double* c = &C[0][0];
    const double* d = &D[0][0];
    double* e  = &E[0][0];
    double* f  = &F[0][0];
    double* g  = &G[0][0];

    // 1st GEMM : E = A * B   (ni x nj)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* e_row = e + i * nj;
        const double* a_row = a + i * nk;
        for (int j = 0; j < nj; ++j) {
            double acc = 0.0;
            for (int k = 0; k < nk; ++k) {
                acc += a_row[k] * b[k * nj + j];
            }
            e_row[j] = acc;
        }
    }

    // 2nd GEMM : F = C * D   (nj x nl)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < nj; ++i) {
        double* f_row = f + i * nl;
        const double* c_row = c + i * nm;
        for (int j = 0; j < nl; ++j) {
            double acc = 0.0;
            for (int k = 0; k < nm; ++k) {
                acc += c_row[k] * d[k * nl + j];
            }
            f_row[j] = acc;
        }
    }

    // 3rd GEMM : G = E * F   (ni x nl)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* g_row = g + i * nl;
        const double* e_row = e + i * nj;
        for (int j = 0; j < nl; ++j) {
            double acc = 0.0;
            for (int k = 0; k < nj; ++k) {
                acc += e_row[k] * f[k * nl + j];
            }
            g_row[j] = acc;
        }
    }
}
