/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum)
{
    // Work with raw pointers to avoid repeated bounds checks
    // and to allow the compiler to better vectorise / optimise.
    //
    // sum is reused across (r,q) pairs; its contents are irrelevant
    // after each outer iteration, so we write directly into it.

