    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {
            // zero the temporary sum array
            for (int p = 0; p < np; ++p)
                sum[p] = 0.0;

            // Perform the inner double sum
            for (int s = 0; s < np; ++s) {
                double a = A[r][q][s];
                const double *crow = C4[s].data();   // C4[s][p] row
                for (int p = 0; p < np; ++p)
                    sum[p] += a * crow[p];
            }

            // Copy the temporary sum back into A[r][q][p]
            double *Apr = A[r][q].data();
            for (int p = 0; p < np; ++p)
                Apr[p] = sum[p];
        }
    }
