```cpp
#include <cmath>
#include <vector>
#include <cstddef>

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev) {
    // Small epsilon to avoid division by zero
    const double eps = 0.1;
    const double inv_n = 1.0 / static_cast<double>(n);
    const double sqrt_n = std::sqrt(static_cast<double>(n));

    // ------------------------------------------------------------------
    // 1) Compute means (parallel over columns)
    // ------------------------------------------------------------------
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean[j] = sum * inv_n;
    }

    // ------------------------------------------------------------------
    // 2) Compute standard deviations (parallel over columns)
    // ------------------------------------------------------------------
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sumsq = 0.0;
        const double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            double d = data[i][j] - mu;
            sumsq += d * d;
        }
        double stdev = std::sqrt(sumsq * inv_n);
        stddev[j] = (stdev <= eps) ? 1.0 : stdev;
    }

    // ------------------------------------------------------------------
    // 3) Center and scale the data (parallel over rows)
    // ------------------------------------------------------------------
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        std::vector<double> &row = data[i];
        for (int j = 0; j < m; ++j) {
            row[j] = (row[j] - mean[j]) / (sqrt_n * stddev[j]);
        }
    }

    // ------------------------------------------------------------------
    // 4) Compute correlation matrix (upper triangle)
    //    The calculation is symmetric, so only compute i<j part
    // ------------------------------------------------------------------
#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m - 1; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double acc = 0.0;
            for (int k = 0; k < n; ++k) {
                acc += data[k][i] * data[k][j];
            }
            corr[i][j] = acc;
            corr[j][i] = acc;   // Symmetry
        }
    }
    corr[m - 1][m - 1] = 1.0;
}
```

