```cpp
#include <vector>
#include <cstdlib>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_ludcmp(int n,
		   std::vector<std::vector<double>>& A,
		   std::vector<double>& b,
		   std::vector<double>& x,
		   std::vector<double>& y)
{
    // Cache row pointers for faster indexing
    std::vector<double*> row(n);
    for (int i = 0; i < n; ++i)
        row[i] = A[i].data();

    /* LU decomposition */
    for (int i = 0; i < n; ++i) {
        double* Ai = row[i];
        const double* Aj;

        /* Sub-diagonal elements */
        for (int j = 0; j < i; ++j) {
            double w = Ai[j];
            Aj = row[j];
#pragma clang loop vectorize(enable)
            for (int k = 0; k < j; ++k) {
                w -= Ai[k] * Aj[k];
            }
            Ai[j] = w / Aj[j];
        }

        /* Row i, columns i..n-1 */
        for (int j = i; j < n; ++j) {
            double w = Ai[j];
#pragma clang loop vectorize(enable)
            for (int k = 0; k < i; ++k) {
                w -= Ai[k] * row[k][j];
            }
            Ai[j] = w;
        }
    }

    /* Forward substitution: A * y = b (lower triangular) */
    for (int i = 0; i < n; ++i) {
        double w = b[i];
#pragma clang loop vectorize(enable)
        for (int j = 0; j < i; ++j) {
            w -= row[i][j] * y[j];
        }
        y[i] = w;
    }

    /* Backward substitution: A * x = y (upper triangular) */
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
#pragma clang loop vectorize(enable)
        for (int j = i + 1; j < n; ++j) {
            w -= row[i][j] * x[j];
        }
        x[i] = w / row[i][i];
    }
}
