void kernel_heat_3d(int tsteps,
                    int n,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<std::vector<double>>>& B)
{
    const double coef = 0.125;
    const int imin = 1, imax = n - 2;
    const int jmin = 1, jmax = n - 2;
    const int kmin = 1, kmax = n - 2;

    for (int t = 1; t <= tsteps; ++t)
    {
        /* A → B */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = imin; i <= imax; ++i)
            for (int j = jmin; j <= jmax; ++j)
                for (int k = kmin; k <= kmax; ++k)
                {
                    double a_ip = A[i+1][j][k];
                    double a_im = A[i-1][j][k];
                    double a_jp = A[i][j+1][k];
                    double a_jm = A[i][j-1][k];
                    double a_kp = A[i][j][k+1];
                    double a_km = A[i][j][k-1];
                    double a_ii = A[i][j][k];

                    B[i][j][k] = coef * (a_ip - 2.0 * a_ii + a_im)
                               + coef * (a_jp - 2.0 * a_ii + a_jm)
                               + coef * (a_kp - 2.0 * a_ii + a_km)
                               + a_ii;
                }

        /* B → A */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = imin; i <= imax; ++i)
            for (int j = jmin; j <= jmax; ++j)
                for (int k = kmin; k <= kmax; ++k)
                {
                    double b_ip = B[i+1][j][k];
                    double b_im = B[i-1][j][k];
                    double b_jp = B[i][j+1][k];
                    double b_jm = B[i][j-1][k];
                    double b_kp = B[i][j][k+1];
                    double b_km = B[i][j][k-1];
                    double b_ii = B[i][j][k];

                    A[i][j][k] = coef * (b_ip - 2.0 * b_ii + b_im)
                               + coef * (b_jp - 2.0 * b_ii + b_jm)
                               + coef * (b_kp - 2.0 * b_ii + b_km)
                               + b_ii;
