                 std::vector<double>& p,
                 std::vector<double>& r) {
    /* Reduce s[j] = Σ_i r[i] * A[i][j]  for j = 0..m-1 */
#pragma omp parallel for reduction(+:s[:m])
    for (int i = 0; i < m; ++i) {
        const double ri = r[i];
        const double *row = A[i].data();
        for (int j = 0; j < m; ++j)
            s[j] += ri * row[j];
    }

    /* Compute sumP = Σ_j p[j]  (independent of i) */
    double sumP = std::accumulate(p.begin(), p.end(), 0.0);

    /* Compute q[i] = Σ_j (A[i][j] + p[j]) = Σ_j A[i][j] + sumP  */
#pragma omp parallel for
    for (int i = 0; i < n; ++i) {
        const double *row = A[i].data();
        double rowSum = 0.0;
        for (int j = 0; j < m; ++j)
            rowSum += row[j];
        q[i] = rowSum + sumP;
    }
}
