#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A,
		      std::vector<std::vector<double>>& B)
{
    // Flatten the two‑dimensional vectors into contiguous one‑dimensional
    // arrays to remove the costly double indirection of std::vector< std::vector<double> >.
    const int N = n * n;
    std::vector<double> a(N), b(N);

    // Copy A into a and B into b
    #pragma omp parallel for
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            a[i * n + j] = A[i][j];

    #pragma omp parallel for
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            b[i * n + j] = B[i][j];

    const double coeff = 0.2;
    const int imax = n - 1;
    const int jmax = n - 1;

    // Main time‑stepping loop
    for (int t = 0; t < tsteps; ++t)
    {
        // First half of the Jacobi update (A -> B)
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < imax; ++i)
        {
            int base = i * n;
            int prev = (i - 1) * n;
            int next = (i + 1) * n;
            for (int j = 1; j < jmax; ++j)
            {
                int idx = base + j;
                b[idx] = coeff * (a[idx] + a[idx - 1] + a[idx + 1]
                               + a[next + j] + a[prev + j]);
            }
        }

        // Second half of the Jacobi update (B -> A)
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < imax; ++i)
        {
            int base = i * n;
            int prev = (i - 1) * n;
            int next = (i + 1) * n;
            for (int j = 1; j < jmax; ++j)
            {
                int idx = base + j;
                a[idx] = coeff * (b[idx] + b[idx - 1] + b[idx + 1]
                               + b[next + j] + b[prev + j]);
            }
        }
    }

    // Copy the results back into the original 2‑D vectors
    #pragma omp parallel for
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            A[i][j] = a[i * n + j];

    #pragma omp parallel for
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            B[i][j] = b[i * n + j];
}
