// Optimized Nussinov kernel – preserves exact semantics
#include <vector>
#include <algorithm>
#include <cassert>
#include <cstdint>
#include <omp.h>

// Helper inline to convert 2‑D indices to a single index
inline std::size_t idx(std::size_t i, std::size_t j, std::size_t n) noexcept {
    return i * n + j;
}

// Wrapper that flattens the 2‑D table into a 1‑D array
// and executes the Nussinov DP in place.
void kernel_nussinov(int n,
                     const std::vector<int>& seq,
                     std::vector<std::vector<int>>& table)
{
    // Sanity checks – they are no‑op in release builds
    assert(static_cast<std::size_t>(n) == seq.size());
    assert(static_cast<std::size_t>(n) == table.size());
    for (int i = 0; i < n; ++i) {
        assert(static_cast<std::size_t>(n) == table[i].size());
    }

    // Flatten the 2‑D table for better cache behaviour
    std::vector<int> flat(n * n);
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            flat[idx(i, j, n)] = table[i][j];

    // Inline match function – no branching
    auto match = [](int a, int b) noexcept -> int {
        return ((a + b) == 3) ? 1 : 0;
    };

    // Main DP: iterate over decreasing i to ensure dependencies
    for (int i = n - 1; i >= 0; --i) {
        // OpenMP directive to parallelise the inner j loop
        // (i+1) is fixed for each iteration of i, so the outer loop stays serial
        #pragma omp parallel for schedule(static, 128) // tune chunk size
        for (int j = i + 1; j < n; ++j) {
            int best = flat[idx(i, j, n)];

            // Update based on neighboring cells
            if (j - 1 >= 0) {
                int v = flat[idx(i, j - 1, n)];
                if (v > best) best = v;
            }
            if (i + 1 < n) {
                int v = flat[idx(i + 1, j, n)];
                if (v > best) best = v;
            }

            // Match or skip between i and j
            if (j - 1 >= 0 && i + 1 < n) {
                int v;
                if (i < j - 1) {
                    v = flat[idx(i + 1, j - 1, n)] + match(seq[i], seq[j]);
                } else {
                    v = flat[idx(i + 1, j - 1, n)];
                }
                if (v > best) best = v;
            }

            // Split at every k between i+1 and j-1
            for (int k = i + 1; k < j; ++k) {
                int v = flat[idx(i, k, n)] + flat[idx(k + 1, j, n)];
                if (v > best) best = v;
            }

            flat[idx(i, j, n)] = best;
        }
    }

    // Copy results back into the original 2‑D vector
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            table[i][j] = flat[idx(i, j, n)];
}
