#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* Based on a Fortran code fragment from Figure 5 of
 * "Automatic Data and Computation Decomposition on Distributed Memory Parallel Computers"
 * by Peizong Lee and Zvi Meir Kedem, TOPLAS, 2002
 */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q) {
    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1  = 2.0;
    const double B2  = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a = -mul1 / 2.0;
    const double b = 1.0 + mul1;
    const double c = a;
    const double d = -mul2 / 2.0;
    const double e = 1.0 + mul2;
    const double f = d;

    /* All inner vectors are assumed contiguous.  We only take a
       pointer to the first element of each row; this keeps the
       original data layout unchanged and allows the compiler to
       generate efficient code. */
    std::vector<double*> u_row(n), v_row(n), p_row(n), q_row(n);
    for (int i = 0; i < n; ++i) {
        u_row[i] = u[i].data();
        v_row[i] = v[i].data();
        p_row[i] = p[i].data();
        q_row[i] = q[i].data();
    }

    const int inner = n - 2;                  // last inner index
    const double one = 1.0;
    const double zero = 0.0;

    /* Main time‑step loop */
    for (int t = 1; t <= tsteps; ++t) {

        /* First sweep: update v, using p/q */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            double* v_i = v_row[i];
            double* p_i = p_row[i];
            double* q_i = q_row[i];
            double* u_i = u_row[i];

            /* Boundary initialization */
            v_i[0] = 1.0;
            p_i[0] = 0.0;
            q_i[0] = v_i[0];

            /* Forward sweep in j (1..n-2) */
            for (int j = 1; j < n - 1; ++j) {
                double denom = a * p_i[j-1] + b;
                p_i[j] = -c / denom;
                q_i[j] = (-d * u_row[j][i - 1] + (one + 2.0 * d) * u_row[j][i]
                          - f * u_row[j][i + 1] - a * q_i[j - 1]) / denom;
            }

            v_i[n-1] = 1.0;

            /* Backward sweep in j */
            for (int j = n-2; j >= 1; --j)
                v_i[j] = p_i[j] * v_i[j+1] + q_i[j];
        }

        /* Second sweep: update u, using p/q */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            double* u_i = u_row[i];
            double* p_i = p_row[i];
            double* q_i = q_row[i];
            double* v_i = v_row[i];

            /* Boundary initialization */
            u_i[0] = 1.0;
            p_i[0] = 0.0;
            q_i[0] = u_i[0];

            /* Forward sweep in j (1..n-2) */
            for (int j = 1; j < n - 1; ++j) {
                double denom = d * p_i[j-1] + e;
                p_i[j] = -f / denom;
                q_i[j] = (-a * v_row[i-1][j] + (one + 2.0 * a) * v_i[j]
                          - c * v_row[i+1][j] - d * q_i[j-1]) / denom;
            }

            u_i[n-1] = 1.0;

            /* Backward sweep in j */
            for (int j = n-2; j >= 1; --j)
                u_i[j] = p_i[j] * u_i[j+1] + q_i[j];
        }
    }
}
