#include <cmath>
#include <vector>
#include <cstring>
#include <omp.h>

/* Optimised kernel for Deriche filtering
 *  * The function signature must match the harness
 */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* ---- Flatten the 2‑D vectors to 1‑D for cache locality ---- */
    const int size = w * h;
    std::vector<float> inFlat(size);
    std::vector<float> outFlat(size);
    std::vector<float> y1Flat(size);
    std::vector<float> y2Flat(size);

    for (int i = 0; i < w; ++i)
        std::memcpy(&inFlat[i * h], imgIn[i].data(), h * sizeof(float));
    for (int i = 0; i < w; ++i)
        std::memcpy(&y1Flat[i * h], y1[i].data(), h * sizeof(float));
    for (int i = 0; i < w; ++i)
        std::memcpy(&y2Flat[i * h], y2[i].data(), h * sizeof(float));

    /* ---- Pre‑compute constants ---- */
    const float exp_a  = std::exp(-alpha);
    const float exp_a2 = std::exp(-2.0 * alpha);
    const float k = 1.0f - exp_a * (1.0f - exp_a) /
                    (1.0f + 2.0f * float(alpha) * exp_a - exp_a2);

    const float a1 = k,                     /* a5 = k */
                a2 = k * exp_a * (float(alpha) - 1.0f),
                a3 = k * exp_a * (float(alpha) + 1.0f),
                a4 = -k * exp_a2,
                a6 = a2,                    /* a6 = a2 */
                a7 = a3,                    /* a7 = a3 */
                a8 = a4;                    /* a8 = a4 */

    const float b1 = std::pow(2.0f, -float(alpha));
    const float b2 = -exp_a2;
    const float c1 = 1.0f, c2 = 1.0f;

    /* ---- Forward vertical  ---- */
    #pragma omp parallel for schedule(static)
    for (int col = 0; col < h; ++col) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        int idx = col;
        for (int row = 0; row < w; ++row, idx += h) {
            float val = inFlat[idx];
            y1Flat[idx] = a1 * val + a2 * xm1 + b1 * ym1 + b2 * ym2;
            xm1 = val;
            ym2 = ym1;
            ym1 = y1Flat[idx];
        }
    }

    /* ---- Backward vertical  ---- */
    #pragma omp parallel for schedule(static)
    for (int col = 0; col < h; ++col) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        int idx = (w-1)*h + col;
        for (int row = w-1; row >= 0; --row, idx -= h) {
            float val = inFlat[idx];
            y2Flat[idx] = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            xp2 = xp1;
            xp1 = val;
            yp2 = yp1;
            yp1 = y2Flat[idx];
        }
    }

    /* ---- Combination 1 (c1=1) ---- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < size; ++i)
        outFlat[i] = y1Flat[i] + y2Flat[i];

    /* ---- Forward horizontal ---- */
    #pragma omp parallel for schedule(static)
    for (int row = 0; row < w; ++row) {
        int base = row * h;
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int col = 0; col < h; ++col) {
            float val = outFlat[base + col];
            y1Flat[base + col] = a5 * val + a6 * tm1 + b1 * ym1 + b2 * ym2;
            tm1 = val;
            ym2 = ym1;
            ym1 = y1Flat[base + col];
        }
    }

    /* ---- Backward horizontal ---- */
    #pragma omp parallel for schedule(static)
    for (int row = 0; row < w; ++row) {
        int base = row * h;
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int col = h-1; col >= 0; --col) {
            float val = outFlat[base + col];
            y2Flat[base + col] = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            tp2 = tp1;
            tp1 = val;
            yp2 = yp1;
            yp1 = y2Flat[base + col];
        }
    }

    /* ---- Final combination (c2=1) ---- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < size; ++i)
        outFlat[i] = y1Flat[i] + y2Flat[i];

    /* ---- Copy result back to the 2‑D vector ---- */
    for (int i = 0; i < w; ++i)
        std::memcpy(imgOut[i].data(), &outFlat[i*h], h * sizeof(float));
}
